    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

    $stmt = $pdo->prepare("SHOW COLUMNS FROM `users` LIKE 'adnumber'");
    $stmt->execute();
    $columnExists = $stmt->fetch(PDO::FETCH_ASSOC);

    if (!$columnExists) {
        $alterSql = "ALTER TABLE `users` ADD `adnumber` INT(11) NOT NULL DEFAULT 1;";
        $pdo->exec($alterSql);
    }

} catch (PDOException $e) {
    echo "Error: " . $e->getMessage();
}

